namespace sv_c10f254d5f27421fb2b1d66866b7b7c3.Services;

/// <summary>
/// Scoped per circuit — each user gets independent warehouse selection.
/// </summary>
public sealed class WarehouseState
{
    public static readonly IReadOnlyList<(string Id, string Name)> AvailableWarehouses =
    [
        ("WH-A", "Warehouse A"),
        ("WH-B", "Warehouse B"),
        ("WH-C", "Warehouse C"),
        ("WH-D", "Warehouse D"),
    ];

    private string _selectedWarehouseId = AvailableWarehouses[0].Id;

    public string SelectedWarehouseId => _selectedWarehouseId;

    public string SelectedWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _selectedWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_selectedWarehouseId == warehouseId) return;
        _selectedWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_c10f254d5f27421fb2b1d66866b7b7c3.Services;

/// <summary>
/// Scoped per circuit. Provides simulated low-stock counts and an event
/// that notifies ALL subscribed components when fresh data arrives.
/// </summary>
public sealed class InventoryAlertService
{
    private static readonly Random _random = new();

    private int _lastCount;

    public int LastCount => _lastCount;

    /// <summary>Fired after <see cref="RefreshAsync"/> fetches new data.</summary>
    public event Action? OnAlertDataChanged;

    /// <summary>Simulates a database query for low-stock items.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        var count = _random.Next(0, 16); // 0–15 inclusive
        return Task.FromResult(count);
    }

    /// <summary>
    /// Fetches fresh data for the given warehouse and notifies all subscribers.
    /// </summary>
    public async Task RefreshAsync(string warehouseId)
    {
        _lastCount = await GetLowStockCountAsync(warehouseId);
        OnAlertDataChanged?.Invoke();
    }
}

@rendermode InteractiveServer
@using sv_c10f254d5f27421fb2b1d66866b7b7c3.Services
@inject WarehouseState WarehouseState
@implements IDisposable

<div class="warehouse-selector px-3 py-2">
    <label class="form-label text-light mb-1 small">Current Warehouse</label>
    <select class="form-select form-select-sm"
            value="@WarehouseState.SelectedWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseState.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
        {
            WarehouseState.SetWarehouse(id);
        }
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

@rendermode InteractiveServer
@using sv_c10f254d5f27421fb2b1d66866b7b7c3.Services
@inject InventoryAlertService AlertService
@implements IDisposable

@if (AlertService.LastCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto">@AlertService.LastCount</span>
}
else
{
    <span class="badge bg-success rounded-pill ms-auto">0</span>
}

@code {
    protected override void OnInitialized()
    {
        AlertService.OnAlertDataChanged += OnDataChanged;
    }

    private void OnDataChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnAlertDataChanged -= OnDataChanged;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@using sv_c10f254d5f27421fb2b1d66866b7b7c3.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard — @WarehouseState.SelectedWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="row mb-4">
    <div class="col-md-4">
        <div class="card shadow-sm">
            <div class="card-body text-center">
                <h5 class="card-title text-muted">Active Warehouse</h5>
                <p class="display-6 fw-bold">@WarehouseState.SelectedWarehouseName</p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card shadow-sm">
            <div class="card-body text-center">
                <h5 class="card-title text-muted">Low-Stock Alerts</h5>
                <p class="display-6 fw-bold @(AlertService.LastCount > 0 ? "text-danger" : "text-success")">
                    @AlertService.LastCount
                </p>
                <small class="text-muted">items below minimum level</small>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card shadow-sm">
            <div class="card-body text-center">
                <h5 class="card-title text-muted">Polling Status</h5>
                <p class="display-6">
                    @if (_polling)
                    {
                        <span class="badge bg-success">Active</span>
                    }
                    else
                    {
                        <span class="badge bg-secondary">Stopped</span>
                    }
                </p>
                <small class="text-muted">refreshes every 10 seconds</small>
            </div>
        </div>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;
    private bool _polling;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        AlertService.OnAlertDataChanged += OnAlertDataChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await StartPollingAsync();
        }
    }

    private async void OnWarehouseChanged()
    {
        // Restart polling for the new warehouse and do an immediate refresh.
        StopPolling();
        await InvokeAsync(async () =>
        {
            await AlertService.RefreshAsync(WarehouseState.SelectedWarehouseId);
            StateHasChanged();
            await StartPollingAsync();
        });
    }

    private void OnAlertDataChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private async Task StartPollingAsync()
    {
        _cts = new CancellationTokenSource();
        _polling = true;
        StateHasChanged();

        var token = _cts.Token;

        // Initial fetch
        await AlertService.RefreshAsync(WarehouseState.SelectedWarehouseId);

        _ = Task.Run(async () =>
        {
            while (!token.IsCancellationRequested)
            {
                try
                {
                    await Task.Delay(TimeSpan.FromSeconds(10), token);
                    await InvokeAsync(async () =>
                    {
                        await AlertService.RefreshAsync(WarehouseState.SelectedWarehouseId);
                    });
                }
                catch (OperationCanceledException)
                {
                    break;
                }
            }
        }, token);
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _polling = false;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        AlertService.OnAlertDataChanged -= OnAlertDataChanged;
        StopPolling();
    }
}

