@page "/dashboard"
@rendermode InteractiveServer
@using sv_c10f254d5f27421fb2b1d66866b7b7c3.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard — @WarehouseState.SelectedWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="row mb-4">
    <div class="col-md-4">
        <div class="card shadow-sm">
            <div class="card-body text-center">
                <h5 class="card-title text-muted">Active Warehouse</h5>
                <p class="display-6 fw-bold">@WarehouseState.SelectedWarehouseName</p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card shadow-sm">
            <div class="card-body text-center">
                <h5 class="card-title text-muted">Low-Stock Alerts</h5>
                <p class="display-6 fw-bold @(AlertService.LastCount > 0 ? "text-danger" : "text-success")">
                    @AlertService.LastCount
                </p>
                <small class="text-muted">items below minimum level</small>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card shadow-sm">
            <div class="card-body text-center">
                <h5 class="card-title text-muted">Polling Status</h5>
                <p class="display-6">
                    @if (_polling)
                    {
                        <span class="badge bg-success">Active</span>
                    }
                    else
                    {
                        <span class="badge bg-secondary">Stopped</span>
                    }
                </p>
                <small class="text-muted">refreshes every 10 seconds</small>
            </div>
        </div>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;
    private bool _polling;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        AlertService.OnAlertDataChanged += OnAlertDataChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await StartPollingAsync();
        }
    }

    private async void OnWarehouseChanged()
    {
        // Restart polling for the new warehouse and do an immediate refresh.
        StopPolling();
        await InvokeAsync(async () =>
        {
            await AlertService.RefreshAsync(WarehouseState.SelectedWarehouseId);
            StateHasChanged();
            await StartPollingAsync();
        });
    }

    private void OnAlertDataChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private async Task StartPollingAsync()
    {
        _cts = new CancellationTokenSource();
        _polling = true;
        StateHasChanged();

        var token = _cts.Token;

        // Initial fetch
        await AlertService.RefreshAsync(WarehouseState.SelectedWarehouseId);

        _ = Task.Run(async () =>
        {
            while (!token.IsCancellationRequested)
            {
                try
                {
                    await Task.Delay(TimeSpan.FromSeconds(10), token);
                    await InvokeAsync(async () =>
                    {
                        await AlertService.RefreshAsync(WarehouseState.SelectedWarehouseId);
                    });
                }
                catch (OperationCanceledException)
                {
                    break;
                }
            }
        }, token);
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _polling = false;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        AlertService.OnAlertDataChanged -= OnAlertDataChanged;
        StopPolling();
    }
}

